from collections import deque

class Solution:
    def minOperations(self, nums):
        n = len(nums)
        target = tuple(range(n))
        start = tuple(nums)
        if start == target:
            return 0
        dist = {start: 0}
        q = deque([start])
        while q:
            cur = q.popleft()
            d = dist[cur]
            for nxt in (cur[::-1], cur[1:] + cur[:1]):
                if nxt not in dist:
                    dist[nxt] = d + 1
                    if nxt == target:
                        return d + 1
                    q.append(nxt)
        return -1

