from collections import deque

class Solution:
    def minOperations(self, nums):
        n = len(nums)
        if n == 1:
            return 0

        def g(x):
            return 0 if x == 0 else n - x

        dist = [[-1] * n, [-1] * n]
        dist[0][0] = 0
        q = deque([(0, 0)])
        while q:
            fam, idx = q.popleft()
            d = dist[fam][idx]
            nidx = (idx - 1) % n
            if dist[fam][nidx] == -1:
                dist[fam][nidx] = d + 1
                q.append((fam, nidx))
            nfam = 1 - fam
            gi = g(idx)
            if dist[nfam][gi] == -1:
                dist[nfam][gi] = d + 1
                q.append((nfam, gi))

        s0 = nums[0]
        if all(nums[i] == (i + s0) % n for i in range(n)):
            return dist[0][s0]
        r0 = n - 1 - s0
        if all(nums[i] == (n - 1 - ((i + r0) % n)) for i in range(n)):
            return dist[1][r0]
        return -1

