var minOperations = function(nums) {
    const n = nums.length;
    if (n === 1) return 0;

    function g(x) {
        return x === 0 ? 0 : n - x;
    }

    const dist = [new Array(n).fill(-1), new Array(n).fill(-1)];
    dist[0][0] = 0;
    const queue = [[0, 0]];
    let qi = 0;
    while (qi < queue.length) {
        const [fam, idx] = queue[qi++];
        const d = dist[fam][idx];
        const nidx = ((idx - 1) % n + n) % n;
        if (dist[fam][nidx] === -1) {
            dist[fam][nidx] = d + 1;
            queue.push([fam, nidx]);
        }
        const nfam = 1 - fam;
        const gi = g(idx);
        if (dist[nfam][gi] === -1) {
            dist[nfam][gi] = d + 1;
            queue.push([nfam, gi]);
        }
    }

    const s0 = nums[0];
    let isIdentity = true;
    for (let i = 0; i < n; i++) {
        if (nums[i] !== (i + s0) % n) { isIdentity = false; break; }
    }
    if (isIdentity) return dist[0][s0];

    const r0 = n - 1 - s0;
    let isReverse = true;
    for (let i = 0; i < n; i++) {
        if (nums[i] !== n - 1 - ((i + r0) % n)) { isReverse = false; break; }
    }
    if (isReverse) return dist[1][r0];

    return -1;
};
